<?php
namespace App\Modules\Hr\Lifecycle\Livewire;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Lifecycle\Actions\CompleteLifecycleTaskAction;use App\Modules\Hr\Lifecycle\Actions\HireCandidateAction;use App\Modules\Hr\Lifecycle\Actions\ManageOffboardingAction;use App\Modules\Hr\Lifecycle\Models\HrOffboardingChecklist;use App\Modules\Hr\Lifecycle\Models\HrOffboardingTask;use App\Modules\Hr\Lifecycle\Models\HrOnboardingChecklist;use App\Modules\Hr\Lifecycle\Models\HrOnboardingTask;use App\Modules\Hr\Personnel\Models\HrEmployee;use App\Modules\Hr\Recruitment\Models\HrJobOffer;use Livewire\Component;
class LifecycleWorkspace extends Component{public array $hireNationalIds=[];public array $taskEvidence=[];public ?int $offboardingEmployeeId=null;public string $lastWorkingOn='';public string $terminationReason='';public function mount():void{$this->lastWorkingOn=today()->addMonth()->toDateString();}public function hire(int $offerId,HireCandidateAction $action):void{$nationalId=(string)($this->hireNationalIds[$offerId]??'');abort_if(blank($nationalId),422,'Kimlik numarası zorunludur.');$action->execute($this->offer($offerId),['national_id'=>$nationalId]);unset($this->hireNationalIds[$offerId]);session()->flash('success','Aday çalışana dönüştürüldü ve onboarding başlatıldı.');}public function startOffboarding(ManageOffboardingAction $action):void{$this->validate(['offboardingEmployeeId'=>'required|integer','lastWorkingOn'=>'required|date','terminationReason'=>'required|string|max:2000']);$action->start($this->employee($this->offboardingEmployeeId),$this->lastWorkingOn,$this->terminationReason);$this->reset(['offboardingEmployeeId','terminationReason']);session()->flash('success','Offboarding kontrol listesi başlatıldı.');}public function completeOnboardingTask(int $id,CompleteLifecycleTaskAction $action):void{$task=HrOnboardingTask::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);$action->execute($task,(string)($this->taskEvidence['on_'.$id]??''));unset($this->taskEvidence['on_'.$id]);}public function completeOffboardingTask(int $id,CompleteLifecycleTaskAction $action):void{$task=HrOffboardingTask::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);$action->execute($task,(string)($this->taskEvidence['off_'.$id]??''));unset($this->taskEvidence['off_'.$id]);}public function closeOffboarding(int $id,ManageOffboardingAction $action):void{$checklist=HrOffboardingChecklist::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);$action->close($checklist);session()->flash('success','Çalışan çıkışı tüm kontrollerle tamamlandı.');}public function render(){ $tenant=app(TenantContext::class)->getId();return view('livewire.hr.lifecycle.lifecycle-workspace',['offers'=>HrJobOffer::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status','approved')->with('application.candidate')->get(),'employees'=>HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->active()->orderBy('first_name')->get(),'onboardings'=>HrOnboardingChecklist::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->with(['employee','tasks'])->latest()->get(),'offboardings'=>HrOffboardingChecklist::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->with(['employee','tasks'])->latest()->get()])->layout('layouts.app');}private function offer(int $id):HrJobOffer{return HrJobOffer::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}private function employee(?int $id):HrEmployee{return HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);}}
